#!/usr/bin/env python3
"""Saturation Mask Encoder for Distributed Inference

Computes, serializes, and embeds saturation masks in model files for deployment.

Saturation masks identify neurons that have frozen/minimal activations during
inference, enabling sparse computation and reduced FFN latency in aether/gnosis.

Module Functions:
  - compute_saturation_masks(): Analyze model layers for frozen neurons
  - encode_masks_to_safetensors(): Embed masks in SafeTensors metadata
  - encode_masks_to_gguf(): Embed masks in GGUF key-value pairs

Methods for saturation detection:
  - variance_gradient: Neuron variance + gradient flow analysis
  - activity_counting: Raw activation count thresholding
  - statistical: Quantile-based activation thresholds

Usage:
  python saturation_mask_encoder.py \
    --model Qwen/Qwen2.5-7B \
    --method variance_gradient \
    --output masks.safetensors \
    --num-samples 512 \
    --variance-threshold 0.01

Requirements:
  - torch >= 2.0
  - transformers >= 5.0
  - safetensors >= 0.4
  - numpy >= 2.0
  - scipy (for statistical analysis)
"""

import argparse
import json
import logging
import pickle
import sys
import time
from collections import defaultdict
from dataclasses import asdict, dataclass
from pathlib import Path
from typing import Any, Dict, List, Optional, Tuple

import numpy as np
import torch
import torch.nn as nn
from safetensors.torch import save_file
from transformers import AutoConfig, AutoModelForCausalLM, AutoTokenizer

logger = logging.getLogger(__name__)
logging.basicConfig(level=logging.INFO, format="%(asctime)s - %(levelname)s - %(message)s")

# Model configurations
MODEL_CONFIGS = {
    "Phi-3-mini": {"hidden_dim": 3072, "ffn_dim": 8192, "num_layers": 32},
    "Qwen/Qwen2.5-7B": {"hidden_dim": 4096, "ffn_dim": 11008, "num_layers": 28},
    "Gemma/gemma-2-9b": {"hidden_dim": 3584, "ffn_dim": 14336, "num_layers": 42},
    "meta-llama/Llama-2-70b-hf": {"hidden_dim": 8192, "ffn_dim": 28672, "num_layers": 80},
}


@dataclass
class LayerFrozenBitmask:
    """Bitmask tracking frozen neurons in a single FFN layer."""

    layer_id: int
    num_neurons: int
    frozen_indices: List[int]

    def to_bytes(self) -> bytes:
        """Serialize bitmask to compact binary format."""
        if not self.frozen_indices:
            return b""

        # Use bitpacking: 1 bit per neuron
        num_bytes = (self.num_neurons + 7) // 8
        data = bytearray(num_bytes)

        for idx in self.frozen_indices:
            if idx < self.num_neurons:
                byte_idx = idx // 8
                bit_idx = idx % 8
                data[byte_idx] |= (1 << bit_idx)

        return bytes(data)

    @staticmethod
    def from_bytes(layer_id: int, num_neurons: int, data: bytes) -> "LayerFrozenBitmask":
        """Deserialize bitmask from binary format."""
        frozen = []
        if data:
            for byte_idx, byte_val in enumerate(data):
                for bit_idx in range(8):
                    if byte_val & (1 << bit_idx):
                        idx = byte_idx * 8 + bit_idx
                        if idx < num_neurons:
                            frozen.append(idx)
        return LayerFrozenBitmask(layer_id, num_neurons, frozen)

    def pct_frozen(self) -> float:
        """Percentage of frozen neurons."""
        return len(self.frozen_indices) / self.num_neurons * 100.0 if self.num_neurons > 0 else 0.0

    def estimated_speedup(self) -> float:
        """Estimate speedup from freezing (linear approximation)."""
        pct = self.pct_frozen() / 100.0
        # Assume ~1% speedup per 10% frozen neurons (conservative lower bound)
        return 1.0 + (pct * 0.1)


@dataclass
class SaturationMasks:
    """Complete saturation masks for all layers in a model."""

    model_name: str
    num_layers: int
    method: str
    created_at: float
    ffn_masks: Dict[int, LayerFrozenBitmask]
    cliff_scores: Dict[int, float]  # Per-layer cliff detection scores
    metadata: Dict[str, Any]

    def to_dict(self) -> Dict[str, Any]:
        """Serialize to JSON-compatible dict."""
        return {
            "model_name": self.model_name,
            "num_layers": self.num_layers,
            "method": self.method,
            "created_at": self.created_at,
            "cliff_scores": self.cliff_scores,
            "metadata": self.metadata,
            "summary": {
                "total_layers": self.num_layers,
                "layers_with_masks": len(self.ffn_masks),
                "avg_pct_frozen": np.mean([m.pct_frozen() for m in self.ffn_masks.values()]),
            }
        }

    def masks_to_bytes(self) -> bytes:
        """Serialize all bitmasks to binary blob for embedding."""
        parts = []

        # Header: num_layers (4 bytes), num_masks (4 bytes)
        parts.append(len(self.ffn_masks).to_bytes(4, "little"))

        # For each mask: layer_id (4), num_neurons (4), data_len (4), data
        for layer_id in sorted(self.ffn_masks.keys()):
            mask = self.ffn_masks[layer_id]
            mask_bytes = mask.to_bytes()

            parts.append(layer_id.to_bytes(4, "little"))
            parts.append(mask.num_neurons.to_bytes(4, "little"))
            parts.append(len(mask_bytes).to_bytes(4, "little"))
            if mask_bytes:
                parts.append(mask_bytes)

        return b"".join(parts)

    @staticmethod
    def masks_from_bytes(data: bytes, num_layers: int) -> Dict[int, LayerFrozenBitmask]:
        """Deserialize bitmasks from binary blob."""
        if not data:
            return {}

        offset = 0
        num_masks = int.from_bytes(data[offset:offset+4], "little")
        offset += 4

        masks = {}
        for _ in range(num_masks):
            layer_id = int.from_bytes(data[offset:offset+4], "little")
            offset += 4
            num_neurons = int.from_bytes(data[offset:offset+4], "little")
            offset += 4
            data_len = int.from_bytes(data[offset:offset+4], "little")
            offset += 4

            mask_bytes = data[offset:offset+data_len] if data_len > 0 else b""
            offset += data_len

            masks[layer_id] = LayerFrozenBitmask.from_bytes(layer_id, num_neurons, mask_bytes)

        return masks


def compute_saturation_masks(
    model: nn.Module,
    tokenizer: Any,
    method: str = "variance_gradient",
    num_samples: int = 512,
    variance_threshold: float = 0.01,
    variance_quantile: float = 0.2,
    batch_size: int = 8,
    device: str = "cuda" if torch.cuda.is_available() else "cpu",
) -> SaturationMasks:
    """
    Compute saturation masks for model FFN layers.

    Args:
        model: HuggingFace transformer model (Qwen, Phi, Gemma, Llama)
        tokenizer: Model tokenizer
        method: Detection method ("variance_gradient", "activity_counting", "statistical")
        num_samples: Number of calibration samples to process
        variance_threshold: Threshold for variance-based detection
        variance_quantile: Quantile for statistical thresholding (0.0-1.0)
        batch_size: Batch size for processing samples
        device: Device to use ("cuda", "cpu")

    Returns:
        SaturationMasks object with frozen neuron indices per layer
    """
    model.to(device)
    model.eval()

    # Detect model architecture
    config = model.config
    model_name = config.model_type or "unknown"
    num_layers = config.num_hidden_layers or 32

    logger.info(f"Computing saturation masks for {model_name} ({num_layers} layers)")
    logger.info(f"Method: {method}, Samples: {num_samples}, Device: {device}")

    # Collect FFN layer activations
    activations = defaultdict(list)
    hooks = []

    def make_hook(layer_id: int):
        def hook(module, input, output):
            # Capture intermediate neuron activations (before final projection)
            if isinstance(output, tuple):
                x = output[0]
            else:
                x = output

            # Detach and move to CPU to save VRAM
            activations[layer_id].append(x.detach().cpu())

        return hook

    # Attach hooks to FFN intermediate layers
    logger.info("Attaching activation hooks...")
    for i, layer in enumerate(model.model.layers if hasattr(model, "model") else model.transformer.h):
        if hasattr(layer, "mlp"):  # Most architectures
            mlp = layer.mlp
            if hasattr(mlp, "up_proj"):
                hook = mlp.up_proj.register_forward_hook(make_hook(i))
                hooks.append(hook)

    # Generate calibration prompts
    logger.info("Generating calibration prompts...")
    calibration_texts = _generate_calibration_prompts(num_samples)

    # Process calibration data
    with torch.no_grad():
        for i in range(0, len(calibration_texts), batch_size):
            batch_texts = calibration_texts[i:i+batch_size]
            try:
                inputs = tokenizer(
                    batch_texts,
                    padding=True,
                    truncation=True,
                    max_length=512,
                    return_tensors="pt"
                )
                inputs = {k: v.to(device) for k, v in inputs.items()}

                # Forward pass to collect activations
                _ = model(**inputs)

                if (i // batch_size + 1) % 10 == 0:
                    logger.info(f"  Processed {i + len(batch_texts)} / {len(calibration_texts)} samples")

            except Exception as e:
                logger.warning(f"Error processing batch: {e}")
                continue

    # Remove hooks
    for hook in hooks:
        hook.remove()

    logger.info("Computing saturation statistics...")

    # Analyze activations per layer
    ffn_masks = {}
    cliff_scores = {}

    for layer_id in sorted(activations.keys()):
        layer_acts = activations[layer_id]

        if not layer_acts:
            logger.warning(f"  Layer {layer_id}: No activations collected")
            continue

        # Concatenate all batch activations
        all_acts = torch.cat(layer_acts, dim=0)  # Shape: (total_tokens, hidden_dim)

        if method == "variance_gradient":
            frozen_indices = _detect_frozen_variance_gradient(
                all_acts,
                threshold=variance_threshold,
                quantile=variance_quantile
            )
        elif method == "activity_counting":
            frozen_indices = _detect_frozen_activity(all_acts, threshold=variance_threshold)
        elif method == "statistical":
            frozen_indices = _detect_frozen_statistical(all_acts, quantile=variance_quantile)
        else:
            raise ValueError(f"Unknown method: {method}")

        # Create bitmask
        num_neurons = all_acts.shape[-1]
        mask = LayerFrozenBitmask(layer_id, num_neurons, frozen_indices)
        ffn_masks[layer_id] = mask

        # Compute cliff score (how sharply frozen counts drop with sequence position)
        cliff_score = _compute_cliff_score(all_acts, frozen_indices)
        cliff_scores[layer_id] = cliff_score

        pct_frozen = mask.pct_frozen()
        speedup = mask.estimated_speedup()
        logger.info(
            f"  Layer {layer_id}: {pct_frozen:.1f}% frozen, "
            f"speedup ~{speedup:.2f}x, cliff={cliff_score:.3f}"
        )

    # Create SaturationMasks object
    masks = SaturationMasks(
        model_name=model_name,
        num_layers=num_layers,
        method=method,
        created_at=time.time(),
        ffn_masks=ffn_masks,
        cliff_scores=cliff_scores,
        metadata={
            "num_samples": num_samples,
            "variance_threshold": variance_threshold,
            "variance_quantile": variance_quantile,
            "device": device,
        }
    )

    return masks


def _generate_calibration_prompts(num_samples: int) -> List[str]:
    """Generate diverse calibration prompts for saturation analysis."""
    prompts = [
        "The quick brown fox jumps over the lazy dog.",
        "Machine learning models learn from data.",
        "Distributed inference enables efficient processing.",
        "Neural networks have multiple layers.",
        "Transformers use attention mechanisms.",
        "Calibration data helps optimize models.",
        "Saturation masks identify frozen neurons.",
        "FFN layers apply non-linear transformations.",
        "Token embeddings represent semantic meaning.",
        "Batch processing improves throughput.",
    ] * (num_samples // 10 + 1)

    return prompts[:num_samples]


def _detect_frozen_variance_gradient(
    activations: torch.Tensor,
    threshold: float = 0.01,
    quantile: float = 0.2
) -> List[int]:
    """Detect frozen neurons using variance and gradient analysis."""
    # Shape: (seq_len, hidden_dim)

    # Compute variance along sequence dimension
    variance = activations.var(dim=0)

    # Compute gradient-like metric (change in activation across positions)
    if activations.shape[0] > 1:
        diffs = torch.abs(activations[1:] - activations[:-1])
        gradient_norm = diffs.mean(dim=0)
    else:
        gradient_norm = torch.zeros_like(variance)

    # Combined metric: neurons with low variance AND low gradient are frozen
    metric = variance + (gradient_norm / (gradient_norm.max() + 1e-8))

    # Threshold via quantile
    threshold_val = torch.quantile(metric, quantile)
    frozen_indices = torch.where(metric < threshold_val)[0].tolist()

    return frozen_indices


def _detect_frozen_activity(
    activations: torch.Tensor,
    threshold: float = 0.01
) -> List[int]:
    """Detect frozen neurons by activity count (near-zero activations)."""
    # Count how many times each neuron is near-zero
    near_zero = (activations.abs() < threshold).sum(dim=0) / activations.shape[0]

    # Neurons that are near-zero >80% of the time are frozen
    frozen_indices = torch.where(near_zero > 0.8)[0].tolist()

    return frozen_indices


def _detect_frozen_statistical(
    activations: torch.Tensor,
    quantile: float = 0.2
) -> List[int]:
    """Detect frozen neurons using statistical quantile analysis."""
    # Compute activation magnitude per neuron
    magnitude = activations.abs().mean(dim=0)

    # Low magnitude neurons are likely frozen
    threshold = torch.quantile(magnitude, quantile)
    frozen_indices = torch.where(magnitude < threshold)[0].tolist()

    return frozen_indices


def _compute_cliff_score(activations: torch.Tensor, frozen_indices: List[int]) -> float:
    """
    Compute cliff detection score (how sharply frozen counts drop over sequence).

    Returns value 0-1, where 1 indicates sharp cliff (all neurons frozen early).
    """
    if not frozen_indices or activations.shape[0] < 2:
        return 0.0

    frozen_set = set(frozen_indices)
    seq_len = activations.shape[0]

    # Track fraction of frozen neurons at each position
    frozen_count_by_pos = []
    for t in range(seq_len):
        count = sum(1 for idx in frozen_set if activations[t, idx].abs() < 0.01)
        frozen_count_by_pos.append(count)

    # Compute derivative of frozen count (how quickly it grows)
    if seq_len > 1:
        diffs = np.diff(frozen_count_by_pos)
        cliff_score = float(np.max(diffs) / (len(frozen_indices) + 1e-8))
    else:
        cliff_score = 0.0

    return min(cliff_score, 1.0)


def encode_masks_to_safetensors(
    model_path: str,
    masks: SaturationMasks,
    output_path: str
) -> None:
    """
    Embed saturation masks in SafeTensors model metadata.

    Args:
        model_path: Path to original .safetensors model file
        masks: SaturationMasks object
        output_path: Output .safetensors file path

    Creates:
        - "__saturation_masks__": binary blob of serialized masks
        - "__cliff_scores__": JSON string of per-layer cliff scores
        - "__saturation_metadata__": JSON string of creation info
    """
    from safetensors import safe_open

    logger.info(f"Loading model from {model_path}...")

    # Load original model tensors
    model_tensors = {}
    with safe_open(model_path, framework="pt", device="cpu") as f:
        for key in f.keys():
            model_tensors[key] = f.get_tensor(key)

    # Serialize masks
    masks_bytes = masks.masks_to_bytes()
    metadata = masks.to_dict()

    logger.info(f"Embedding {len(masks.ffn_masks)} saturation masks...")
    logger.info(f"  Serialized masks: {len(masks_bytes) / 1024:.1f} KB")
    logger.info(f"  Metadata: {len(json.dumps(metadata)) / 1024:.1f} KB")

    # Prepare metadata (stored as special tensors or in header)
    # Using special tensor keys that start with "__"
    model_tensors["__saturation_masks_blob__"] = torch.from_numpy(
        np.frombuffer(masks_bytes, dtype=np.uint8)
    )

    # Save updated model
    logger.info(f"Writing output to {output_path}...")
    save_file(model_tensors, output_path)

    # Write metadata JSON alongside the model
    metadata_path = str(output_path).replace(".safetensors", ".saturation.json")
    with open(metadata_path, "w") as f:
        json.dump(metadata, f, indent=2)
    logger.info(f"Metadata saved to {metadata_path}")


def encode_masks_to_gguf(
    gguf_path: str,
    masks: SaturationMasks,
    output_path: str
) -> None:
    """
    Embed saturation masks in GGUF model file.

    GGUF embedding strategy:
      - "model.saturation_masks": binary blob (uint8 array)
      - "model.saturation_method": string
      - "model.saturation_timestamp": float
      - Per-layer cliff scores: "model.cliff_score.{layer_id}": float

    Args:
        gguf_path: Path to input .gguf model file
        masks: SaturationMasks object
        output_path: Output .gguf file path
    """
    try:
        from gguf import GGUFReader, GGUFWriter
    except ImportError:
        logger.error("gguf module not available. Install via: pip install gguf")
        return

    logger.info(f"Loading GGUF model from {gguf_path}...")

    # Read original GGUF
    reader = GGUFReader(gguf_path)

    # Create writer with same header info
    writer = GGUFWriter(output_path, reader.arch)

    # Copy existing metadata
    for key in reader.metadata:
        writer.add_string(key, str(reader.metadata[key]))

    # Add saturation metadata
    logger.info("Embedding saturation masks in GGUF...")

    masks_bytes = masks.masks_to_bytes()
    writer.add_array("model.saturation_masks", np.frombuffer(masks_bytes, dtype=np.uint8))
    writer.add_string("model.saturation_method", masks.method)
    writer.add_float32("model.saturation_timestamp", masks.created_at)

    # Add cliff scores per layer
    for layer_id, score in masks.cliff_scores.items():
        writer.add_float32(f"model.cliff_score.{layer_id}", score)

    # Copy tensors
    for tensor_name in reader.tensor_names:
        logger.info(f"  Copying tensor {tensor_name}...")
        tensor_data = reader.get_tensor(tensor_name)
        writer.add_tensor(tensor_name, tensor_data)

    writer.close()
    logger.info(f"GGUF output saved to {output_path}")


def main():
    parser = argparse.ArgumentParser(
        description="Compute and embed saturation masks in model files"
    )
    parser.add_argument(
        "--model",
        type=str,
        required=True,
        help="Model ID or path (e.g., Qwen/Qwen2.5-7B)"
    )
    parser.add_argument(
        "--method",
        type=str,
        choices=["variance_gradient", "activity_counting", "statistical"],
        default="variance_gradient",
        help="Saturation detection method"
    )
    parser.add_argument(
        "--output",
        type=str,
        required=True,
        help="Output file path (.safetensors or .gguf)"
    )
    parser.add_argument(
        "--num-samples",
        type=int,
        default=512,
        help="Number of calibration samples"
    )
    parser.add_argument(
        "--variance-threshold",
        type=float,
        default=0.01,
        help="Variance threshold for detection"
    )
    parser.add_argument(
        "--variance-quantile",
        type=float,
        default=0.2,
        help="Quantile for statistical thresholding (0.0-1.0)"
    )
    parser.add_argument(
        "--batch-size",
        type=int,
        default=8,
        help="Batch size for processing"
    )
    parser.add_argument(
        "--device",
        type=str,
        choices=["cuda", "cpu"],
        default="cuda" if torch.cuda.is_available() else "cpu",
        help="Device to use"
    )
    parser.add_argument(
        "--save-pickle",
        type=str,
        default=None,
        help="Also save masks as pickle file"
    )

    args = parser.parse_args()

    # Load model and tokenizer
    logger.info(f"Loading model: {args.model}")
    try:
        model = AutoModelForCausalLM.from_pretrained(
            args.model,
            torch_dtype=torch.float16 if args.device == "cuda" else torch.float32,
            device_map="auto" if args.device == "cuda" else None,
        )
        tokenizer = AutoTokenizer.from_pretrained(args.model)
    except Exception as e:
        logger.error(f"Failed to load model: {e}")
        sys.exit(1)

    # Compute masks
    try:
        masks = compute_saturation_masks(
            model=model,
            tokenizer=tokenizer,
            method=args.method,
            num_samples=args.num_samples,
            variance_threshold=args.variance_threshold,
            variance_quantile=args.variance_quantile,
            batch_size=args.batch_size,
            device=args.device,
        )
    except Exception as e:
        logger.error(f"Failed to compute masks: {e}")
        sys.exit(1)

    # Encode to output format
    output_path = Path(args.output)
    output_path.parent.mkdir(parents=True, exist_ok=True)

    try:
        if str(output_path).endswith(".safetensors"):
            encode_masks_to_safetensors(args.model, masks, str(output_path))
        elif str(output_path).endswith(".gguf"):
            encode_masks_to_gguf(args.model, masks, str(output_path))
        else:
            logger.warning(f"Unknown output format: {output_path}")
            # Default to pickle
            with open(output_path, "wb") as f:
                pickle.dump(masks, f)
    except Exception as e:
        logger.error(f"Failed to encode masks: {e}")
        sys.exit(1)

    # Optional pickle save
    if args.save_pickle:
        logger.info(f"Saving pickle to {args.save_pickle}...")
        pickle.dump(masks, open(args.save_pickle, "wb"))

    # Print summary
    logger.info("\n" + "="*60)
    logger.info("SATURATION MASK COMPUTATION SUMMARY")
    logger.info("="*60)
    for layer_id, mask in sorted(masks.ffn_masks.items()):
        logger.info(
            f"Layer {layer_id:3d}: {mask.pct_frozen():5.1f}% frozen, "
            f"speedup ~{mask.estimated_speedup():.2f}x"
        )
    logger.info("="*60)


if __name__ == "__main__":
    main()
